import{_ as o,o as r,c as i,a0 as a}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"Choose an Image-Processing Provider","description":"","frontmatter":{},"headers":[],"relativePath":"imports/choose-provider.md","filePath":"imports/choose-provider.md"}'),s={name:"imports/choose-provider.md"};function t(n,e,l,c,h,u){return r(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="choose-an-image-processing-provider" tabindex="-1">Choose an Image-Processing Provider <a class="header-anchor" href="#choose-an-image-processing-provider" aria-label="Permalink to &quot;Choose an Image-Processing Provider&quot;">​</a></h1><p>The imports page lets eligible users choose how screenshot images are processed.</p><blockquote><p>Screenshot placeholder: ocr-providers.png</p></blockquote><h2 id="your-three-options" tabindex="-1">Your three options <a class="header-anchor" href="#your-three-options" aria-label="Permalink to &quot;Your three options&quot;">​</a></h2><h3 id="free-local-processing" tabindex="-1">Free Local Processing <a class="header-anchor" href="#free-local-processing" aria-label="Permalink to &quot;Free Local Processing&quot;">​</a></h3><p>Use Free Local Processing when:</p><ul><li>the screenshot is clean and readable</li><li>you want the default option</li><li>you do not want to use an external API key</li></ul><p>This is the default path. It is good enough for many normal screenshots, but the app itself warns that manual review is recommended.</p><h3 id="gemini" tabindex="-1">Gemini <a class="header-anchor" href="#gemini" aria-label="Permalink to &quot;Gemini&quot;">​</a></h3><p>Use Gemini when:</p><ul><li>text is small</li><li>names are harder to read</li><li>the screenshot includes CJK characters or trickier formatting</li><li>you want the strongest recognition quality</li></ul><p>Gemini usually gives the best OCR results, but it requires <strong>your own API key</strong>.</p><h3 id="premium-processing" tabindex="-1">Premium Processing <a class="header-anchor" href="#premium-processing" aria-label="Permalink to &quot;Premium Processing&quot;">​</a></h3><p>Premium Processing is <strong>coming soon</strong>.</p><p>Right now:</p><ul><li>it may appear on the page</li><li>it is not available as a working processing engine</li><li>you should not plan an active workflow around it yet</li></ul><h2 id="quick-guidance" tabindex="-1">Quick guidance <a class="header-anchor" href="#quick-guidance" aria-label="Permalink to &quot;Quick guidance&quot;">​</a></h2><p>Choose:</p><ul><li><strong>Free Local Processing</strong> for quick, ordinary, readable screenshots</li><li><strong>Gemini</strong> for harder screenshots or when accuracy matters more</li><li><strong>Premium Processing</strong> never, for now, because it is not live yet</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./gemini-key.html">Set Up Your Gemini API Key</a></li><li><a href="./upload-screenshots.html">Upload Screenshots</a></li><li><a href="./../admin/ocr-settings.html">Administer OCR Providers</a></li></ul>',21)])])}const m=o(s,[["render",t]]);export{p as __pageData,m as default};
